package com.promonts.dto;import com.promonts.domain.workspace.Workspace;import lombok.*;import java.time.LocalDateTime;@Data @NoArgsConstructor @AllArgsConstructor @Builder public class WorkspaceResponse{private Long id;private String name;private String description;private CourseInfo course;private String notes;private LocalDateTime createdAt;private LocalDateTime lastAccessedAt;@Data @AllArgsConstructor public static class CourseInfo{private Long id;private String name;private String code;}public static WorkspaceResponse from(Workspace workspace){CourseInfo courseInfo=null;if(workspace.getCourse()!=null){courseInfo=new CourseInfo(workspace.getCourse().getId(),workspace.getCourse().getName(),workspace.getCourse().getCode());}return WorkspaceResponse.builder().id(workspace.getId()).name(workspace.getName()).description(workspace.getDescription()).course(courseInfo).notes(workspace.getNotes()).createdAt(workspace.getCreatedAt()).lastAccessedAt(workspace.getLastAccessedAt()).build();}}
